import{_ as s,o as i,c as t,a2 as a}from"./chunks/framework.C_beXv0I.js";const u=JSON.parse('{"title":"Install","description":"","frontmatter":{},"headers":[],"relativePath":"guides/install.md","filePath":"guides/install.md","lastUpdated":1783011651000}'),n={name:"guides/install.md"};function o(l,e,r,d,h,p){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h1><p>Muster has two parts that install together: a deterministic CLI (an npm package) and a Claude Code plugin. The CLI does the routing math; the plugin teaches Claude Code how to drive a run.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><a href="https://claude.com/claude-code" target="_blank" rel="noreferrer">Claude Code</a></li><li>Node.js 20 or newer (<code>node --version</code>)</li></ul><p>Muster runs on your interactive Claude Code subscription. There is no separate model API, no runtime to deploy, and no key to manage.</p><h2 id="_1-run-the-installer" tabindex="-1">1. Run the installer <a class="header-anchor" href="#_1-run-the-installer" aria-label="Permalink to &quot;1. Run the installer&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p><code>install</code> mutates nothing in your <code>~/.claude</code>. It only prints the steps it cannot do for you, because registering a plugin is a Claude Code action, not a shell command.</p><h2 id="_2-register-the-plugin" tabindex="-1">2. Register the plugin <a class="header-anchor" href="#_2-register-the-plugin" aria-label="Permalink to &quot;2. Register the plugin&quot;">​</a></h2><p>Run these inside Claude Code:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Adnova-Group/muster</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # register the marketplace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> muster@muster</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # install the plugin</span></span></code></pre></div><p>Muster&#39;s glass-box output style ships <strong>inside the plugin</strong> and applies automatically when the plugin is enabled (it sets <code>force-for-plugin: true</code>), so there is no style command to run. The old <code>/output-style &lt;name&gt;</code> command was removed from Claude Code in v2.1.91; auto-apply replaces it. To pick a different style at any time, use <code>/config</code> and select <strong>Output style</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Restart to activate</p><p>Plugin install is a Claude Code action, so the running session only picks Muster up after you (re)install it through <code>/plugin</code>. The plugin&#39;s agents, the three session hooks, and the output style become active in your next fresh session (restart or <code>/clear</code>).</p></div><h2 id="_3-verify" tabindex="-1">3. Verify <a class="header-anchor" href="#_3-verify" aria-label="Permalink to &quot;3. Verify&quot;">​</a></h2><p>Start a new Claude Code session and run:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/muster:run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> limiting</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> public</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> with</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests</span></span></code></pre></div><p>Muster detects your project, assembles a crew, and shows the glass-box manifest plus a plan, then stops for your approval. If you see the crew manifest, you are set.</p><p>You can also exercise the CLI directly in a terminal. Every verb is plain Node and prints JSON:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> detect</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> capabilities</span></span></code></pre></div><h2 id="what-the-plugin-adds" tabindex="-1">What the plugin adds <a class="header-anchor" href="#what-the-plugin-adds" aria-label="Permalink to &quot;What the plugin adds&quot;">​</a></h2><ul><li><strong>Four slash commands</strong>: <code>/muster:run</code>, <code>/muster:autopilot</code>, <code>/muster:diagnose</code>, <code>/muster:audit</code>.</li><li><strong>Four session hooks</strong>, all declared in <code>plugin/hooks/hooks.json</code> and active only while Muster is enabled: <ul><li><strong><code>SessionStart</code></strong> prepends Muster&#39;s working principles, the four verbs, a routing-policy reminder, and a one-line project detect to every session. Never writes to your <code>~/.claude</code> files.</li><li><strong><code>UserPromptSubmit</code></strong> injects periodic drift-reinforcement nudges (every <code>MUSTER_NUDGE_EVERY</code> turns) and full principle reminders (every <code>MUSTER_NUDGE_EVERY * MUSTER_PRINCIPLES_EVERY</code> turns) so sessions stay on-model after compaction or long runs.</li><li><strong><code>PreToolUse</code></strong> enforces two gates. While a wave is active (<code>.muster/wave-active</code> present), file writes from the orchestrator main loop are blocked, with behaviour controlled by <code>MUSTER_WAVE_GUARD</code> (<code>deny</code> / <code>warn</code> / <code>off</code>). After a run ends (no wave marker), a per-turn post-run scale gate (<code>MUSTER_INLINE_SCALE</code>, default 3) denies the Nth distinct inline file write in a single turn and routes it to a verb instead -- closing the drift window the advisory nudge alone cannot hold. Writes into <code>.muster/</code> and <code>.claude/</code> (in-cwd repo) are always exempt so orchestrator bookkeeping and repo-local settings are never blocked.</li><li><strong><code>PreToolUse</code> on <code>Task</code></strong> enforces the todo-driving gate. During a live run (<code>.muster/run-active</code> present), a subagent-wave dispatch is denied unless a native todo list was written since the run started, so plan progress stays visible in Claude Code&#39;s todo UI. Controlled by <code>MUSTER_TODO_GATE</code> (<code>deny</code> / <code>warn</code> / <code>off</code>); biased hard toward allow -- any uncertainty allows.</li></ul></li><li><strong>Built-in agents and skills</strong>, vendored from MIT-licensed upstreams plus Muster&#39;s own clean-room specialists.</li></ul><h2 id="uninstall" tabindex="-1">Uninstall <a class="header-anchor" href="#uninstall" aria-label="Permalink to &quot;Uninstall&quot;">​</a></h2><p>Because everything Muster adds lives <strong>inside the plugin</strong>, removal is mostly a matter of removing the plugin. Muster never writes to your <code>~/.claude/CLAUDE.md</code> or <code>settings.json</code>, so there is nothing tangled to unpick.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span></span></code></pre></div><p><code>uninstall</code> prints the steps it cannot do for you, because removing a plugin is a Claude Code action:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> muster@muster</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # remove the plugin (and its style + hook)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> muster</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # remove the marketplace</span></span></code></pre></div><p>It also cleans up after older Muster versions: if a pre-<code>force-for-plugin</code> install left a copied style at <code>~/.claude/output-styles/muster.md</code>, <code>uninstall</code> removes it (and restores the original it had displaced, if there is a <code>.bak</code>). On a current install there is nothing there to remove.</p><div class="tip custom-block"><p class="custom-block-title">Everything leaves with the plugin</p><p>The output style (<code>force-for-plugin</code>) and all three session hooks are plugin-native, so uninstalling the plugin removes them automatically. The forced style auto-reverts to whatever output style you had before. There is no global file or <code>CLAUDE.md</code> block to clean up by hand.</p></div><p>Next: the <a href="/muster/guides/quickstart">Quickstart</a>.</p>`,29)])])}const g=s(n,[["render",o]]);export{u as __pageData,g as default};
